// Read transcript file from webhook body or file path
const inputData = items[0].json;
const fs = require('fs');
const path = require('path');

let transcriptPath = inputData.file_path;
if (!transcriptPath) {
  // If no file_path, check for inline transcript text
  if (inputData.transcript_text) {
    // Write to temp file
    transcriptPath = '/tmp/transcript_' + Date.now() + '.txt';
    fs.writeFileSync(transcriptPath, inputData.transcript_text);
  } else {
    throw new Error('No file_path or transcript_text provided');
  }
}

// Verify file exists
if (!fs.existsSync(transcriptPath)) {
  throw new Error('Transcript file not found: ' + transcriptPath);
}

return [{ json: { file_path: transcriptPath, timestamp: new Date().toISOString() } }];

// Parse the extracted memo from command output
const stdout = items[0].json.stdout;
try {
  const memo = JSON.parse(stdout);
  return [{ json: { memo, account_id: memo.account_id, company_name: memo.company_name } }];
} catch (e) {
  throw new Error('Failed to parse memo JSON: ' + e.message + '\nOutput: ' + stdout);
}

// Generate agent spec from memo
const memo = items[0].json.memo;
const { generateAgentSpec } = require('/scripts/generate_agent');
const spec = generateAgentSpec(memo);
return [{ json: { memo, spec, account_id: memo.account_id } }];

// Write outputs to storage
const fs = require('fs');
const path = require('path');
const data = items[0].json;
const outputDir = path.join('/outputs/accounts', data.account_id, 'v1');

// Create directory
fs.mkdirSync(outputDir, { recursive: true });

// Write memo
fs.writeFileSync(path.join(outputDir, 'memo.json'), JSON.stringify(data.memo, null, 2));

// Write agent spec
fs.writeFileSync(path.join(outputDir, 'agent_spec.json'), JSON.stringify(data.spec, null, 2));

return [{ json: { 
  status: 'success', 
  account_id: data.account_id,
  version: 'v1',
  outputs: {
    memo: path.join(outputDir, 'memo.json'),
    agent_spec: path.join(outputDir, 'agent_spec.json')
  }
} }];

// Create task tracker entry
const fs = require('fs');
const data = items[0].json;
const tasksFile = '/outputs/tasks.json';

let tasks = { tasks: [] };
if (fs.existsSync(tasksFile)) {
  tasks = JSON.parse(fs.readFileSync(tasksFile, 'utf-8'));
}

const task = {
  id: 'TASK-' + String(tasks.tasks.length + 1).padStart(3, '0'),
  account_id: data.account_id,
  version: 'v1',
  status: 'completed',
  pipeline: 'Pipeline A (Demo → Agent)',
  created_at: new Date().toISOString(),
  updated_at: new Date().toISOString()
};

tasks.tasks.push(task);
fs.writeFileSync(tasksFile, JSON.stringify(tasks, null, 2));

return [{ json: { ...data, task } }];
